import { hasBrowsersSupported } from '../../../tool';
import { useMount } from '../../../hooks';

export interface UseCompatibleDecoratorOptions {
    onUnsupportedVersion: () => void;
    onUnsupportedBrowser: () => void;
    getConfig: () => Promise<string>;
}


// 兼容性装饰器
export const useCompatibleDecorator = ({ onUnsupportedBrowser, onUnsupportedVersion, getConfig }: UseCompatibleDecoratorOptions) => {
    useMount(async () => {
        // 这里还是建议用谷歌浏览器
        if (!navigator.userAgent.includes('Chrome')) {
            return onUnsupportedBrowser()
        }
        const data = await getConfig()
        // 这里判断兼容的浏览器和版本
        if (!hasBrowsersSupported(navigator.userAgent, data)) {
            return onUnsupportedVersion()
        }
    });
};
